import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class Solution {
    public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
        Map<String, Integer> businessOrderMap = new HashMap<>();
        businessOrderMap.put("electronics", 0);
        businessOrderMap.put("grocery", 1);
        businessOrderMap.put("pharmacy", 2);
        businessOrderMap.put("restaurant", 3);

        List<String[]> validCoupons = new ArrayList<>();

        for (int i = 0; i < code.length; i++) {
            String c = code[i];
            String bl = businessLine[i];
            boolean a = isActive[i];

            if (c != null && !c.isEmpty() && c.matches("^[\\w]+$") && 
                bl != null && (bl.equals("electronics") || bl.equals("grocery") || bl.equals("pharmacy") || bl.equals("restaurant")) && a) {
                validCoupons.add(new String[]{c, bl});
            }
        }

        validCoupons.sort((a, b) -> {
            int orderA = businessOrderMap.get(a[1]);
            int orderB = businessOrderMap.get(b[1]);
            if (orderA != orderB) {
                return Integer.compare(orderA, orderB);
            } else {
                return a[0].compareTo(b[0]);
            }
        });

        String[] result = new String[validCoupons.size()];
        for (int i = 0; i < result.length; i++) {
            result[i] = validCoupons.get(i)[0];
        }

        return result;
    }
}
